import React, { useEffect, useState } from "react";
import Sidebar from "../../components/Sidebar";
import API from "../../api/api";

const FindProjects = () => {

  const [projects, setProjects] = useState([]);
  const [search, setSearch] = useState("");
  const [loading, setLoading] = useState(true);

  // ===============================
  // FETCH PROJECTS
  // ===============================
  const fetchProjects = async () => {
    try {
      const res = await API.get("/projects");
      setProjects(res.data);
    } catch (err) {
      console.log(err);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchProjects();
  }, []);

  // ===============================
  // SEND PROPOSAL
  // ===============================
  const sendProposal = async (projectId) => {
    const bid = prompt("Enter Your Bid Amount");
    const message = prompt("Enter Proposal Message");

    if (!bid || !message) return;

    try {
      await API.post("/proposals", {
        project_id: projectId,
        bid,
        message
      });

      alert("Proposal Sent Successfully");
    } catch (error) {
      alert("Error sending proposal");
    }
  };

  const filteredProjects = projects.filter((project) =>
    project.title?.toLowerCase().includes(search.toLowerCase())
  );

  return (
    <div className="bg-gray-100 min-h-screen">

      {/* Sidebar */}
      <Sidebar />

      {/* Main Content */}
      <div className="ml-64 p-8">

        <h1 className="text-3xl font-bold mb-6">
          Find Projects
        </h1>

        {/* Search */}
        <input
          type="text"
          placeholder="Search projects..."
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          className="w-full mb-8 px-4 py-3 border rounded-xl shadow-sm focus:outline-none focus:ring-2 focus:ring-green-400"
        />

        {loading && <p>Loading projects...</p>}

        {!loading && filteredProjects.length === 0 && (
          <p>No Projects Found</p>
        )}

        {/* Project Grid */}
        <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-8">
          {filteredProjects.map((project) => (
            <div
              key={project.id}
              className="bg-white p-6 rounded-2xl shadow hover:shadow-xl transition duration-300"
            >
              <h3 className="text-xl font-semibold mb-3">
                {project.title}
              </h3>

              <p className="text-gray-600 mb-4">
                {project.description}
              </p>

              <p className="text-blue-600 font-bold mb-6">
                Budget: ₹{project.budget}
              </p>

              <button
                onClick={() => sendProposal(project.id)}
                className="w-full bg-green-500 text-white py-2 rounded-lg hover:bg-green-600 transition"
              >
                Send Proposal
              </button>
            </div>
          ))}
        </div>

      </div>
    </div>
  );
};

export default FindProjects;
